import type { Request, Response, NextFunction } from "express";
import type { CastError } from "mongoose";
import { databaseErrorConverter } from "@utils/error-helpers";
import { SearchOrdersRequest } from "@api/api"
import OrderService from "@services/orders";

/**
 * Url parameters generated by the search form (they are the same)
 */
export type IGetAllOrdersParameters = Partial<Record<keyof SearchOrdersRequest, string>>;

/**
 * Max items per page
 */
const paginationPageSize = Number.parseInt(process.env.NODE_SETTINGS_PAGINATION_PAGE_SIZE ?? "10");

/**
 * Get ALL orders info
 * Only of current user if NOT admin
 *
 * @param request
 * @param response
 * @param next
 */
export const pageAllOrders = async (request: Request & {
    params: IGetAllOrdersParameters
}, response: Response, next: NextFunction) => {
    // current page
    const paginationCurrentPage = Number.parseInt(request.params.page ?? "1");
    return OrderService.search(
        {
            ...request.params,
            page: paginationCurrentPage,
            pageSize: paginationPageSize,
        },
        // Only admin can see non-active and (soft) deleted products
        request.session.user?.admin
            ? {}
            : { active: true, deletedAt: undefined }
    )
        .then(({ items, meta }) =>
            response.render("orders/search", {
                pageMetaTitle: "All Orders",
                pageMetaLinks: [ "/css/order-list.css" ],
                orderList: items,
                search: {
                    ...request.query,
                    page: meta.page,
                    pageSize: meta.pageSize
                },
            })
        )
        .catch((error: Error | CastError) => next(databaseErrorConverter(error)));
};